-- MODIFICA TIPO GREZZO/NOBILITATO IN ANAGRAFICA ARTICOLI PREESISTENTE (PER RETROCOMPATIBILITA' STATISTICHE DI MAGAZZINO)
/*
UPDATE U_ART_AN
SET 
	ART_TIPOG = CASE ART_TIPOG WHEN '' THEN ''
				ELSE '0'+ ART_TIPOG
				END,
	ART_TIPON = CASE ART_TIPON WHEN '' THEN ''
				ELSE '0'+ ART_TIPON
				END
WHERE ART_CODPRI IN (SELECT ART_CODPRI FROM U_ART_PR WHERE ART_CODMAT = '008' AND LEN(RTRIM(ART_CODPRI)) = 15 AND (LEN(RTRIM(ART_TIPOG)) = 1 OR LEN(RTRIM(ART_TIPON)) = 1))
*/
SELECT ART_TIPOG,ART_TIPON,* FROM U_ART_AN 
WHERE 
ART_CODPRI IN (SELECT ART_CODPRI FROM U_ART_PR WHERE ART_CODMAT = '008' AND LEN(RTRIM(ART_CODPRI)) = 15) 
ORDER BY ART_CODPRI


