-- CHIUSURA PACKING LIST APERTE ESISTENTI
--UPDATE PROD_PACKING SET FLGDDT = 1 WHERE FLGDDT = 0
SELECT * FROM PROD_PACKING WHERE FLGDDT = 0


-- CHIUSURA PROGRAMMI DI PRODUZIONE APERTI (SOLO NOBILITATURA)
--UPDATE PRODUZIONE SET FLGCLOSED = 1 WHERE PARENT = '' AND FLGCLOSED = 0 AND IDPRG IN (SELECT IDPRG FROM PROD_AVANZA WHERE FASELA = 'NOBILI')
SELECT * FROM PRODUZIONE WHERE IDPRG IN (SELECT IDPRG FROM PRODUZIONE WHERE PARENT = '' AND FLGCLOSED = 0) AND IDPRG IN (SELECT IDPRG FROM PROD_AVANZA WHERE FASELA = 'NOBILI') ORDER BY IDPRG DESC


-- CREAZIONE DISTINTE BASE SPESSORE 10 PER OGNI NUOVO GRUPPO PRODUTTIVO
/*
