-- DISATTIVAZIONE GRUPPI PRODUTTIVI SENZA DI.BA.
UPDATE PARA SET DISATTIVO = 1 WHERE CODICE LIKE 'PRDP_ACQ_E0-%'
UPDATE PARA SET DISATTIVO = 1 WHERE CODICE LIKE 'PRDP_ACQ_PL_E0-%'
UPDATE PARA SET DISATTIVO = 1 WHERE CODICE LIKE 'PRDP_FUO_E0-%'
UPDATE PARA SET DISATTIVO = 1 WHERE CODICE LIKE 'PRDP_LGN_E0-%'
